#include <stdio.h>
#include <string.h>

#define STACK_CAPACITY 101
char stackArray[STACK_CAPACITY];
int topIndex;

int isEmpty() { return topIndex == -1; }
int isFull() { return topIndex >= STACK_CAPACITY - 1; }
void push(char c) { if (!isFull()) stackArray[++topIndex] = c; }
char pop() { return isEmpty() ? '\0' : stackArray[topIndex--]; }

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    for (int tc = 0; tc < T; ++tc) {
        char line[STACK_CAPACITY];
        if (!fgets(line, STACK_CAPACITY, stdin)) line[0] = '\0';
        line[strcspn(line, "\n")] = '\0'; // remove trailing newline
        int n = strlen(line);
        topIndex = -1;
        for (int i = 0; i < n; ++i) push(line[i]);
        char out[STACK_CAPACITY];
        int idx = 0;
        while (!isEmpty()) out[idx++] = pop();
        out[idx] = '\0';
        printf("%s\n", out);
    }
    return 0;
}

