import java.io.*;

public class Main {
    private static final int STACK_CAPACITY = 101;
    private static final char[] stack = new char[STACK_CAPACITY];
    private static int top;

    private static boolean isEmpty() { return top == -1; }
    private static boolean isFull() { return top >= STACK_CAPACITY - 1; }
    private static void push(char c) { if (!isFull()) stack[++top] = c; }
    private static char pop() { return isEmpty() ? '\0' : stack[top--]; }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        int T = line == null || line.isEmpty() ? 0 : Integer.parseInt(line.trim());
        for (int tc = 0; tc < T; ++tc) {
            String s = br.readLine();
            if (s == null) s = "";
            top = -1;
            for (int i = 0; i < s.length(); ++i) push(s.charAt(i));
            StringBuilder sb = new StringBuilder();
            while (!isEmpty()) sb.append(pop());
            System.out.println(sb.toString());
        }
    }
}

